class RateLimiter:
    def __init__(self, max_requests, window_sec):
        self.max = max_requests
        self.window = window_sec
        self.requests = []

    def allow(self):
        now = time.time()
        # Remove old requests
        self.requests = [t for t in self.requests if t > now - self.window]
        if len(self.requests) < self.max:
            self.requests.append(now)
            return True
        return False
